package main

import (
	"log"
	"math/rand"
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "Duration of HTTP requests in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"user_id", "endpoint", "method", "status", "request_id"},
	)

	requestCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"user_id", "endpoint", "method", "status", "user_agent", "ip_address"},
	)

	activeUsers = prometheus.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "active_users",
			Help: "Number of active users",
		},
		[]string{"user_id", "session_id", "region", "device_type"},
	)

	dataProcessed = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "data_processed_bytes_total",
			Help: "Total bytes of data processed",
		},
		[]string{"user_id", "operation", "data_type", "source"},
	)

	userOperations = prometheus.NewSummaryVec(
		prometheus.SummaryOpts{
			Name:       "user_operation_duration_seconds",
			Help:       "Duration of user operations",
			Objectives: map[float64]float64{0.5: 0.05, 0.9: 0.01, 0.99: 0.001},
		},
		[]string{"user_id", "operation_type", "resource_id", "tenant_id"},
	)

	errorCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "errors_total",
			Help: "Total number of errors",
		},
		[]string{"user_id", "error_type", "error_code", "endpoint", "severity"},
	)
)

func init() {
	prometheus.MustRegister(requestDuration)
	prometheus.MustRegister(requestCounter)
	prometheus.MustRegister(activeUsers)
	prometheus.MustRegister(dataProcessed)
	prometheus.MustRegister(userOperations)
	prometheus.MustRegister(errorCounter)
}

func trackRequest(userID, endpoint, method, status, requestID, userAgent, ipAddress string, duration float64) {
	requestDuration.WithLabelValues(userID, endpoint, method, status, requestID).Observe(duration)
	requestCounter.WithLabelValues(userID, endpoint, method, status, userAgent, ipAddress).Inc()
}

func trackActiveUser(userID, sessionID, region, deviceType string) {
	activeUsers.WithLabelValues(userID, sessionID, region, deviceType).Inc()
}

func trackDataProcessed(userID, operation, dataType, source string, bytes float64) {
	dataProcessed.WithLabelValues(userID, operation, dataType, source).Add(bytes)
}

func trackUserOperation(userID, operationType, resourceID, tenantID string, duration float64) {
	userOperations.WithLabelValues(userID, operationType, resourceID, tenantID).Observe(duration)
}

func trackError(userID, errorType, errorCode, endpoint, severity string) {
	errorCounter.WithLabelValues(userID, errorType, errorCode, endpoint, severity).Inc()
}

func apiHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	endpoint := r.URL.Path
	method := r.Method
	requestID := r.Header.Get("X-Request-ID")
	if requestID == "" {
		requestID = generateRequestID()
	}
	userAgent := r.Header.Get("User-Agent")
	ipAddress := r.RemoteAddr

	sessionID := r.URL.Query().Get("session_id")
	if sessionID == "" {
		sessionID = "default_session"
	}
	region := r.URL.Query().Get("region")
	if region == "" {
		region = "unknown"
	}
	deviceType := r.URL.Query().Get("device_type")
	if deviceType == "" {
		deviceType = "unknown"
	}

	trackActiveUser(userID, sessionID, region, deviceType)

	operation := r.URL.Query().Get("operation")
	if operation == "" {
		operation = "read"
	}
	dataType := r.URL.Query().Get("data_type")
	if dataType == "" {
		dataType = "json"
	}
	source := r.URL.Query().Get("source")
	if source == "" {
		source = "api"
	}

	bytesProcessed := float64(rand.Intn(10000) + 1000)
	trackDataProcessed(userID, operation, dataType, source, bytesProcessed)

	resourceID := r.URL.Query().Get("resource_id")
	if resourceID == "" {
		resourceID = "default_resource"
	}
	tenantID := r.URL.Query().Get("tenant_id")
	if tenantID == "" {
		tenantID = "default_tenant"
	}

	operationStart := time.Now()
	time.Sleep(time.Duration(rand.Intn(100)) * time.Millisecond)
	operationDuration := time.Since(operationStart).Seconds()
	trackUserOperation(userID, operation, resourceID, tenantID, operationDuration)

	status := "200"
	if rand.Float32() < 0.1 {
		status = "500"
		trackError(userID, "internal_error", "ERR_500", endpoint, "high")
	} else if rand.Float32() < 0.05 {
		status = "404"
		trackError(userID, "not_found", "ERR_404", endpoint, "low")
	}

	duration := time.Since(start).Seconds()
	trackRequest(userID, endpoint, method, status, requestID, userAgent, ipAddress, duration)

	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Request processed successfully"))
}

func generateRequestID() string {
	const charset = "abcdefghijklmnopqrstuvwxyz0123456789"
	b := make([]byte, 16)
	for i := range b {
		b[i] = charset[rand.Intn(len(charset))]
	}
	return string(b)
}

func simulateTraffic() {
	ticker := time.NewTicker(1 * time.Second)
	defer ticker.Stop()

	users := []string{"user1", "user2", "user3", "user4", "user5"}
	endpoints := []string{"/api/data", "/api/users", "/api/products", "/api/orders"}
	regions := []string{"us-east", "us-west", "eu-central", "ap-south"}
	deviceTypes := []string{"mobile", "desktop", "tablet", "iot"}
	operations := []string{"read", "write", "update", "delete"}
	dataTypes := []string{"json", "xml", "csv", "binary"}

	for range ticker.C {
		userID := users[rand.Intn(len(users))]
		endpoint := endpoints[rand.Intn(len(endpoints))]
		region := regions[rand.Intn(len(regions))]
		deviceType := deviceTypes[rand.Intn(len(deviceTypes))]
		operation := operations[rand.Intn(len(operations))]
		dataType := dataTypes[rand.Intn(len(dataTypes))]

		sessionID := userID + "_session_" + string(rune(rand.Intn(10)+'0'))
		requestID := generateRequestID()
		resourceID := "resource_" + string(rune(rand.Intn(100)+'0'))
		tenantID := "tenant_" + string(rune(rand.Intn(5)+'0'))

		duration := rand.Float64() * 2
		trackRequest(userID, endpoint, "GET", "200", requestID, "SimulatedAgent/1.0", "127.0.0.1", duration)
		trackActiveUser(userID, sessionID, region, deviceType)
		trackDataProcessed(userID, operation, dataType, "simulation", float64(rand.Intn(5000)+500))
		trackUserOperation(userID, operation, resourceID, tenantID, rand.Float64())

		if rand.Float32() < 0.05 {
			trackError(userID, "timeout", "ERR_TIMEOUT", endpoint, "medium")
		}
	}
}

func main() {
	rand.Seed(time.Now().UnixNano())

	go simulateTraffic()

	http.HandleFunc("/api/", apiHandler)
	http.Handle("/metrics", promhttp.Handler())

	log.Println("Starting server on :8080")
	log.Println("Metrics available at http://localhost:8080/metrics")
	log.Println("API endpoint at http://localhost:8080/api/")
	log.Fatal(http.ListenAndServe(":8080", nil))
}